//! Integration tests for RWKV7Pipeline.
//!
//! Uses tiny synthetic dimensions so tests run in-process with no I/O.

use distributed_inference::loader::{KnotConfig, OwnedBytes, WeightBackend};
use distributed_inference::model_rwkv7::{RWKV7Config, RWKV7LayerState, RWKV7Pipeline};
use std::any::Any;
use std::collections::HashMap;
use std::sync::Arc;

// ─────────────────────────────────────────────────────────────────────────────
// Mock backend (same shape as in mamba_integration_test)
// ─────────────────────────────────────────────────────────────────────────────

struct MockBackend {
    store: HashMap<String, Vec<u8>>,
}

impl MockBackend {
    fn new() -> Self {
        Self {
            store: HashMap::new(),
        }
    }

    fn insert_f32(&mut self, name: &str, v: Vec<f32>) {
        let bytes: Vec<u8> = v.iter().flat_map(|f| f.to_le_bytes()).collect();
        self.store.insert(name.to_string(), bytes.clone());
        self.store.insert(format!("{name}.bin"), bytes);
    }

    fn fill(&mut self, name: &str, n: usize, seed: f32) {
        let v: Vec<f32> = (0..n).map(|i| (i as f32 * seed).sin() * 0.05).collect();
        self.insert_f32(name, v);
    }

    fn fill_ones(&mut self, name: &str, n: usize) {
        self.insert_f32(name, vec![1.0f32; n]);
    }

    fn into_arc(self) -> Arc<dyn WeightBackend> {
        Arc::new(self)
    }
}

unsafe impl Send for MockBackend {}
unsafe impl Sync for MockBackend {}

impl WeightBackend for MockBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        let key = if self.store.contains_key(name) {
            name.to_string()
        } else if self.store.contains_key(bare) {
            bare.to_string()
        } else {
            return Err(format!("MockBackend: missing {name:?}"));
        };
        Ok(OwnedBytes::Owned(Arc::new(self.store[&key].clone())))
    }

    fn has_tensor(&self, name: &str) -> bool {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        self.store.contains_key(name) || self.store.contains_key(bare)
    }

    fn as_any(&self) -> &dyn Any {
        self
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Test dimensions — deliberately tiny
// ─────────────────────────────────────────────────────────────────────────────

const D: usize = 32; // hidden_dim
const N_HEADS: usize = 4; // rwkv_n_heads
const HEAD_SIZE: usize = 8; // D / N_HEADS
const LRW: usize = 4; // low_rank_w / low_rank_a / low_rank_v
const GATE_INNER: usize = 16;
const FFN_INNER: usize = 128;
const VOCAB: usize = 64;
const LAYERS: usize = 2;

fn rwkv7_knot_config() -> KnotConfig {
    serde_json::from_str(&format!(
        r#"{{
        "hidden_dim": {D}, "num_layers": {LAYERS}, "num_heads": {N_HEADS},
        "num_kv_heads": {N_HEADS}, "head_dim": {HEAD_SIZE},
        "intermediate_size": {FFN_INNER}, "vocab_size": {VOCAB},
        "arch": "rwkv7",
        "rwkv_n_heads": {N_HEADS},
        "rwkv_low_rank_w": {LRW}, "rwkv_low_rank_a": {LRW}, "rwkv_low_rank_v": {LRW},
        "rwkv_gate_inner": {GATE_INNER}
    }}"#
    ))
    .unwrap()
}

fn build_rwkv7_backend() -> MockBackend {
    let mut b = MockBackend::new();

    b.fill("token_embd_weight", VOCAB * D, 0.01);
    // output_norm uses LayerNorm — needs a weight of ones and bias of zeros
    b.fill_ones("output_norm_weight", D);
    b.insert_f32("output_norm_bias", vec![0.0f32; D]);
    b.fill("output_weight", VOCAB * D, 0.02);

    for l in 0..LAYERS {
        let n = |s: &str| format!("blk_{l}_{s}");

        // Layer norms
        b.fill_ones(&n("ln1_weight"), D);
        b.insert_f32(&n("ln1_bias"), vec![0.0f32; D]);
        b.fill_ones(&n("ln2_weight"), D);
        b.insert_f32(&n("ln2_bias"), vec![0.0f32; D]);

        // Time-mixing mix ratios (small values so sigmoid stays near 0.5)
        for tag in &["mix_r", "mix_w", "mix_k", "mix_v", "mix_a", "mix_g"] {
            b.fill(&n(&format!("rwkv_{tag}")), D, 0.05);
        }

        // Main projections [D, D]
        b.fill(&n("rwkv_r_weight"), D * D, 0.03);
        b.fill(&n("rwkv_k_weight"), D * D, 0.03);
        b.fill(&n("rwkv_v_weight"), D * D, 0.03);
        b.fill(&n("rwkv_o_weight"), D * D, 0.03);

        // Dynamic decay: w0[D], w1[LRW, D], w2[D, LRW]
        b.fill(&n("rwkv_w0"), D, -0.5);
        b.fill(&n("rwkv_w1"), LRW * D, 0.02);
        b.fill(&n("rwkv_w2"), D * LRW, 0.02);

        // Dynamic attention: a0[D], a1[LRW, D], a2[D, LRW]
        b.fill(&n("rwkv_a0"), D, 0.0);
        b.fill(&n("rwkv_a1"), LRW * D, 0.02);
        b.fill(&n("rwkv_a2"), D * LRW, 0.02);

        // Value versioning: v0[D], v1[LRW, D], v2[D, LRW]
        b.fill(&n("rwkv_v0"), D, 0.0);
        b.fill(&n("rwkv_v1"), LRW * D, 0.02);
        b.fill(&n("rwkv_v2"), D * LRW, 0.02);

        // Key adjustment scalars
        b.fill(&n("rwkv_k_k"), D, 0.5);
        b.fill(&n("rwkv_k_a"), D, 0.5);
        b.fill(&n("rwkv_r_k"), D, 0.1);

        // Gate: g1[GATE_INNER, D], g2[D, GATE_INNER]
        b.fill(&n("rwkv_g1_weight"), GATE_INNER * D, 0.03);
        b.fill(&n("rwkv_g2_weight"), D * GATE_INNER, 0.03);

        // Group norm (ln_x)
        b.fill_ones(&n("rwkv_ln_x_weight"), D);
        b.insert_f32(&n("rwkv_ln_x_bias"), vec![0.0f32; D]);

        // Channel-mixing
        b.fill(&n("ffn_mix_k"), D, 0.05);
        b.fill(&n("ffn_mix_r"), D, 0.05);
        b.fill(&n("ffn_k_weight"), FFN_INNER * D, 0.02);
        b.fill(&n("ffn_v_weight"), D * FFN_INNER, 0.02);
        b.fill(&n("ffn_r_weight"), D * D, 0.02);
    }
    b
}

