#[test]
fn rwkv7_config_from_knot_config() {
    let cfg = RWKV7Config::from_knot(&rwkv7_knot_config());
    assert_eq!(cfg.hidden_dim, D);
    assert_eq!(cfg.num_layers, LAYERS);
    assert_eq!(cfg.vocab_size, VOCAB);
    assert_eq!(cfg.n_heads, N_HEADS);
    assert_eq!(cfg.head_size, HEAD_SIZE);
    assert_eq!(cfg.low_rank_w, LRW);
    assert_eq!(cfg.gate_inner, GATE_INNER);
    assert_eq!(cfg.ffn_inner, FFN_INNER);
}

#[test]
fn knot_config_rwkv7_fields_roundtrip() {
    let json = r#"{
        "hidden_dim": 2560, "num_layers": 32, "num_heads": 32, "num_kv_heads": 32,
        "head_dim": 80, "intermediate_size": 10240, "vocab_size": 65536,
        "arch": "rwkv7",
        "rwkv_n_heads": 32, "rwkv_low_rank_w": 32,
        "rwkv_low_rank_a": 32, "rwkv_low_rank_v": 32, "rwkv_gate_inner": 128
    }"#;
    let cfg: KnotConfig = serde_json::from_str(json).unwrap();
    assert_eq!(cfg.arch, "rwkv7");
    assert_eq!(cfg.rwkv_n_heads, Some(32));
    assert_eq!(cfg.rwkv_low_rank_w, Some(32));
    assert_eq!(cfg.rwkv_gate_inner, Some(128));
    // Transformer fields absent
    assert_eq!(cfg.d_state, None);
}

#[test]
fn rwkv7_pipeline_forward_produces_finite_logits() {
    let cfg = rwkv7_knot_config();
    let backend = build_rwkv7_backend().into_arc();
    let mut pipeline = RWKV7Pipeline::from_knot(&cfg, backend);

    let mut logits = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut logits);

    assert_eq!(logits.len(), VOCAB);
    assert!(
        logits.iter().all(|v| v.is_finite()),
        "RWKV-7 logits contain NaN/Inf"
    );
}

#[test]
fn rwkv7_pipeline_state_changes_across_tokens() {
    let cfg = rwkv7_knot_config();
    let backend = build_rwkv7_backend().into_arc();
    let mut pipeline = RWKV7Pipeline::from_knot(&cfg, backend);

    let mut l0 = vec![0.0f32; VOCAB];
    let mut l1 = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut l0);
    pipeline.forward_one(5, &mut l1);

    let changed = l0.iter().zip(&l1).any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(
        changed,
        "RWKV-7 logits identical across tokens — state not updating"
    );
}

#[test]
fn rwkv7_pipeline_reset_reproduces_first_output() {
    let cfg = rwkv7_knot_config();
    let backend = build_rwkv7_backend().into_arc();
    let mut pipeline = RWKV7Pipeline::from_knot(&cfg, backend);

    let mut out_first = vec![0.0f32; VOCAB];
    let mut out_mid = vec![0.0f32; VOCAB];
    let mut out_reset = vec![0.0f32; VOCAB];

    pipeline.forward_one(0, &mut out_first);
    pipeline.forward_one(3, &mut out_mid);
    pipeline.reset_states();
    pipeline.forward_one(0, &mut out_reset);

    for (a, b) in out_first.iter().zip(&out_reset) {
        assert!((a - b).abs() < 1e-5, "reset+replay mismatch: {a} vs {b}");
    }
    let mid_differs = out_first
        .iter()
        .zip(&out_mid)
        .any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(mid_differs, "Mid-run output should differ from first");
}

#[test]
fn rwkv7_wkv_state_accumulates() {
    // After N tokens, the WKV state (wkv) should be non-zero (the state
    // absorbs information from each token via v ⊗ k updates).
    let cfg = rwkv7_knot_config();
    let backend = build_rwkv7_backend().into_arc();
    let mut pipeline = RWKV7Pipeline::from_knot(&cfg, backend);

    let mut logits = vec![0.0f32; VOCAB];
    for tok in 0..5u32 {
        pipeline.forward_one(tok % VOCAB as u32, &mut logits);
    }

    // At least one layer's WKV state should be nonzero.
    let any_nonzero = pipeline
        .states
        .iter()
        .any(|s| s.wkv.iter().any(|&v| v != 0.0));
    assert!(any_nonzero, "WKV state remains zero after 5 tokens");
}

#[test]
fn rwkv7_batched_forward_parity() {
    // The width-axis amortization must change THROUGHPUT, not RESULTS. A batched
    // n-lane forward must produce, per lane, the bit-identical logits of n separate
    // single-sequence `forward_one` runs. Divergent per-lane token sequences exercise
    // the batch-isolation (no lane bleeds into another via the shared weight reads).
    let cfg = rwkv7_knot_config();
    let seqs: [&[u32]; 4] = [&[0, 5, 2, 9], &[7, 1, 3, 4], &[2, 2, 8, 0], &[6, 4, 1, 5]];
    let n = seqs.len();
    let steps = seqs[0].len();

    // Solo reference: one independent pipeline per lane.
    let mut solo_logits: Vec<Vec<f32>> = vec![vec![0.0f32; VOCAB]; n];
    for k in 0..n {
        let mut p = RWKV7Pipeline::from_knot(&cfg, build_rwkv7_backend().into_arc());
        for t in 0..steps {
            p.forward_one(seqs[k][t], &mut solo_logits[k]);
        }
    }

    // Batched: one pipeline, n lanes sharing the resident weights.
    let batched = RWKV7Pipeline::from_knot(&cfg, build_rwkv7_backend().into_arc());
    let mut states = batched.new_batch_states(n);
    let mut batch_logits: Vec<Vec<f32>> = vec![vec![0.0f32; VOCAB]; n];
    for t in 0..steps {
        let toks: Vec<u32> = (0..n).map(|k| seqs[k][t]).collect();
        batched.forward_one_batch(&toks, &mut states, &mut batch_logits);
    }

    for k in 0..n {
        assert_eq!(
            solo_logits[k], batch_logits[k],
            "lane {k}: batched forward is not bit-identical to solo forward_one"
        );
    }
}

#[test]
fn rwkv7_batched_stream_station_parity() {
    // Station-side batching: one weight page (build_layer_weights_part) applied to ALL
    // lanes via stream_layer_*_batch must be bit-identical, per lane, to N solo stream
    // forwards over the same layer range. This is the windmill's ~L× lever proven correct.
    let cfg = rwkv7_knot_config();
    let (a, b) = (0usize, LAYERS); // the station's layer range (here: whole model)
    let inputs: Vec<Vec<f32>> = vec![
        (0..D).map(|i| (i as f32 * 0.01).sin()).collect(),
        (0..D).map(|i| (i as f32 * 0.02).cos()).collect(),
        (0..D).map(|i| (i as f32 * 0.013 + 1.0).sin()).collect(),
    ];
    let n = inputs.len();

    // Solo: N independent streaming pipelines, each runs the range on its own stream_x.
    let mut solo_out: Vec<Vec<f32>> = Vec::new();
    for k in 0..n {
        let mut p = RWKV7Pipeline::from_knot_streaming(&cfg, build_rwkv7_backend().into_arc());
        p.reset_states();
        p.set_stream_x(inputs[k].clone());
        p.set_stream_v_first(Vec::new());
        for l in a..b {
            p.stream_layer_timemix(l);
            p.stream_layer_channelmix(l);
        }
        solo_out.push(p.stream_x_ref().to_vec());
    }

    // Batched: ONE streaming pipeline, external N-lane state ([layer][lane]).
    let batched = RWKV7Pipeline::from_knot_streaming(&cfg, build_rwkv7_backend().into_arc());
    let mut xs: Vec<Vec<f32>> = inputs.clone();
    let mut vfs: Vec<Vec<f32>> = vec![Vec::new(); n];
    let mut states: Vec<Vec<RWKV7LayerState>> = (0..LAYERS)
        .map(|_| (0..n).map(|_| RWKV7LayerState::new(D, N_HEADS, HEAD_SIZE)).collect())
        .collect();
    for l in a..b {
        batched.stream_layer_timemix_batch(l, &mut xs, &mut vfs, &mut states[l]);
        batched.stream_layer_channelmix_batch(l, &mut xs, &mut states[l]);
    }

    for k in 0..n {
        assert_eq!(solo_out[k], xs[k], "lane {k}: batched stream != solo stream (bitwise)");
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Lane lifecycle + batched lm_head (Leg B1: continuous batching)
// ─────────────────────────────────────────────────────────────────────────────

/// A page-able backend: the MockBackend store behind a Mutex so the test can play
/// host and set `lm_head_shard` AFTER pipelines hold the Arc — the native mirror
/// of the wasm host's `set_tensor` paging flow.
struct PagedBackend {
    inner: std::sync::Mutex<MockBackend>,
}

impl PagedBackend {
    fn set_f32(&self, name: &str, v: Vec<f32>) {
        self.inner.lock().unwrap().insert_f32(name, v);
    }
}

impl WeightBackend for PagedBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        self.inner.lock().unwrap().fetch_tensor(name)
    }
    fn has_tensor(&self, name: &str) -> bool {
        self.inner.lock().unwrap().has_tensor(name)
    }
    fn as_any(&self) -> &dyn Any {
        self
    }
}

/// Run the station's layer range once over the whole wave (one "token" hop).
fn run_range(
    p: &RWKV7Pipeline,
    a: usize,
    b: usize,
    xs: &mut [Vec<f32>],
    vfs: &mut [Vec<f32>],
    states: &mut [Vec<RWKV7LayerState>],
) {
    for l in a..b {
        p.stream_layer_timemix_batch(l, xs, vfs, &mut states[l]);
        p.stream_layer_channelmix_batch(l, xs, &mut states[l]);
    }
}

#[test]
fn rwkv7_batched_shard_lm_head_parity() {
    // The batched vocab-shard sweep (one dequant per row, all lanes) must return,
    // per lane, the bit-identical [best_idx, best_val] pair of a solo
    // stream_logits_begin + stream_logits_shard over the same residual — across
    // MULTIPLE shards and lanes with DISTINCT states.
    let cfg = rwkv7_knot_config();
    let inputs: Vec<Vec<f32>> = vec![
        (0..D).map(|i| (i as f32 * 0.017).sin()).collect(),
        (0..D).map(|i| (i as f32 * 0.031).cos()).collect(),
        (0..D).map(|i| (i as f32 * 0.011 + 0.7).sin()).collect(),
    ];
    let n = inputs.len();

    // One shared page-able backend; the test pages each lm_head shard in turn.
    let paged = Arc::new(PagedBackend { inner: std::sync::Mutex::new(build_rwkv7_backend()) });
    let backend: Arc<dyn WeightBackend> = paged.clone();

    // Solo reference: one pipeline per lane, final norm cached via the solo begin.
    let mut solos: Vec<RWKV7Pipeline> = (0..n)
        .map(|_| RWKV7Pipeline::from_knot(&cfg, backend.clone()))
        .collect();
    for (k, p) in solos.iter_mut().enumerate() {
        p.set_stream_x(inputs[k].clone());
        p.stream_logits_begin();
    }

    // Batched: one pipeline, the lanes' final-normed residuals in one wave.
    let batched = RWKV7Pipeline::from_knot(&cfg, backend.clone());
    let normed: Vec<Vec<f32>> = inputs.iter().map(|x| batched.final_norm(x)).collect();

    // The shard rows are output_weight rows (f32) — same fill formula as the fixture.
    let out_w: Vec<f32> = (0..VOCAB * D).map(|i| (i as f32 * 0.02).sin() * 0.05).collect();
    let shards = [(0u32, 32u32), (32u32, 64u32)];
    for &(lo, hi) in &shards {
        paged.set_f32(
            "lm_head_shard",
            out_w[(lo as usize) * D..(hi as usize) * D].to_vec(),
        );
        let flat = batched.stream_logits_shard_batch(lo, hi, &normed);
        assert_eq!(flat.len(), 2 * n, "shard [{lo}, {hi}): flat pair count");
        for k in 0..n {
            let solo_pair = solos[k].stream_logits_shard(lo, hi);
            assert_eq!(
                &flat[2 * k..2 * k + 2],
                solo_pair.as_slice(),
                "lane {k} shard [{lo}, {hi}): batched shard pair != solo (bitwise)"
            );
        }
    }
}

#[test]
fn rwkv7_batch_lane_lifecycle_parity() {
    // Continuous batching's license: wave MEMBERSHIP must not affect any lane's
    // math. Removing a lane (swap_remove) leaves the survivors' subsequent outputs
    // bit-identical to a wave that never contained it; a lane added mid-wave
    // matches a fresh solo run; neither disturbs the other lanes.
    let cfg = rwkv7_knot_config();
    let (a, b) = (0usize, LAYERS);
    // Lane `k`'s token-`t` residual input (the host re-embeds per token).
    let x_tok = |k: usize, t: usize| -> Vec<f32> {
        (0..D)
            .map(|i| ((i as f32) * 0.01 * (k as f32 + 1.0) + t as f32 * 0.37).sin())
            .collect()
    };

    // ── Wave A: lanes {0,1,2} built via batch_add_lane; lane 1 leaves after token 0.
    let p = RWKV7Pipeline::from_knot_streaming(&cfg, build_rwkv7_backend().into_arc());
    let mut xs: Vec<Vec<f32>> = Vec::new();
    let mut vfs: Vec<Vec<f32>> = Vec::new();
    let mut states = p.new_batch_states_range(0, a, b); // width-0 skeleton
    for k in 0..3 {
        let lane = p.batch_add_lane(&mut xs, &mut vfs, &mut states, a, b);
        assert_eq!(lane, k, "batch_add_lane must append");
        xs[lane] = x_tok(k, 0);
    }
    run_range(&p, a, b, &mut xs, &mut vfs, &mut states);
    let moved = RWKV7Pipeline::batch_remove_lane(&mut xs, &mut vfs, &mut states, 1);
    assert_eq!(moved, 2, "old last lane (2) must have moved into slot 1");
    assert_eq!(xs.len(), 2);
    // Token 1 for the survivors: lane 0 stays at slot 0, old lane 2 now at slot 1.
    xs[0] = x_tok(0, 1);
    xs[1] = x_tok(2, 1);
    vfs.iter_mut().for_each(|v| v.clear());
    run_range(&p, a, b, &mut xs, &mut vfs, &mut states);

    // ── Wave B (reference): lanes {0,2} only — lane 1 NEVER existed. A fresh lane
    // joins before token 1 (zero state, its own first token).
    let pr = RWKV7Pipeline::from_knot_streaming(&cfg, build_rwkv7_backend().into_arc());
    let mut rxs: Vec<Vec<f32>> = Vec::new();
    let mut rvfs: Vec<Vec<f32>> = Vec::new();
    let mut rstates = pr.new_batch_states_range(0, a, b);
    for (slot, k) in [0usize, 2usize].into_iter().enumerate() {
        let lane = pr.batch_add_lane(&mut rxs, &mut rvfs, &mut rstates, a, b);
        assert_eq!(lane, slot);
        rxs[lane] = x_tok(k, 0);
    }
    run_range(&pr, a, b, &mut rxs, &mut rvfs, &mut rstates);
    let joiner = pr.batch_add_lane(&mut rxs, &mut rvfs, &mut rstates, a, b);
    assert_eq!(joiner, 2);
    rxs[0] = x_tok(0, 1);
    rxs[1] = x_tok(2, 1);
    rxs[2] = x_tok(7, 1); // the joiner's FIRST token
    rvfs.iter_mut().for_each(|v| v.clear());
    run_range(&pr, a, b, &mut rxs, &mut rvfs, &mut rstates);

    // Survivors: swap-removed wave == never-had-the-lane wave, bitwise (residual AND
    // recurrent state) — and the mid-wave join didn't disturb them either.
    for slot in 0..2 {
        assert_eq!(
            xs[slot], rxs[slot],
            "slot {slot}: residual differs after remove/add lifecycle (isolation broken)"
        );
        for l in a..b {
            assert_eq!(
                states[l][slot].wkv, rstates[l][slot].wkv,
                "slot {slot} layer {l}: wkv state differs after lifecycle"
            );
        }
    }

    // The joiner matches a fresh SOLO pipeline running only its own token.
    let mut ps = RWKV7Pipeline::from_knot_streaming(&cfg, build_rwkv7_backend().into_arc());
    ps.reset_states();
    ps.set_stream_x(x_tok(7, 1));
    ps.set_stream_v_first(Vec::new());
    for l in a..b {
        ps.stream_layer_timemix(l);
        ps.stream_layer_channelmix(l);
    }
    assert_eq!(
        rxs[2],
        ps.stream_x_ref().to_vec(),
        "joined lane != fresh solo run (bitwise)"
    );

    // batch_reset_lane zeroes exactly that lane's range state (fresh sequence in-slot).
    RWKV7Pipeline::batch_reset_lane(&mut rstates, 0, a, b);
    for l in a..b {
        let s = &rstates[l][0];
        assert!(s.wkv.iter().all(|&v| v == 0.0), "layer {l}: wkv not zeroed");
        assert!(s.shift_x.iter().all(|&v| v == 0.0), "layer {l}: shift_x not zeroed");
        assert!(s.channel_state.iter().all(|&v| v == 0.0), "layer {l}: channel_state not zeroed");
        assert!(s.v_first.is_empty(), "layer {l}: v_first not cleared");
        // ...and the OTHER lanes kept theirs (isolation).
        assert!(
            rstates[l][1].wkv.iter().any(|&v| v != 0.0),
            "layer {l}: reset bled into lane 1"
        );
    }
}

#[test]
fn rwkv7_lane_state_equals_solo_state() {
    // The batch-lane ↔ solo BRIDGE contract: after the same token sequence, a
    // whole-pipe wave lane's per-layer recurrent state is BIT-IDENTICAL to a solo
    // run's — so the `snapshot_state` frame carries either interchangeably (the
    // wasm `snapshot_lane_state` / `restore_lane_state` exports). `snapshot_state`
    // itself is wasm-only; here we (a) compare the RWKV7LayerState arrays directly,
    // (b) hand-assemble the exact frame from BOTH sides via the pub f16_codec
    // helpers and assert byte-equality, and (c) prove restore-roundtrip
    // continuation equality in BOTH directions (lane frame → solo, solo frame →
    // fresh lane). Lean: Gnosis.InferenceMachineResume.checkpoint_resume.
    use distributed_inference::f16_codec::{put_f32s, put_u32, take_f32s, take_u32};

    let cfg = rwkv7_knot_config();
    let seq: [u32; 4] = [3, 11, 7, 2]; // the shared prefix
    let cont: [u32; 4] = [5, 9, 1, 6]; // the continuation

    // Solo: K tokens through forward_one.
    let mut solo = RWKV7Pipeline::from_knot(&cfg, build_rwkv7_backend().into_arc());
    let mut solo_logits = vec![0.0f32; VOCAB];
    for &t in &seq {
        solo.forward_one(t, &mut solo_logits);
    }

    // Whole-pipe wave: lane 0 runs the SAME tokens; a decoy lane 1 runs different
    // ones (the lane must match solo DESPITE riding a real 2-wide wave).
    let batched = RWKV7Pipeline::from_knot(&cfg, build_rwkv7_backend().into_arc());
    let mut bstates = batched.new_batch_states(2);
    let mut blogits = vec![vec![0.0f32; VOCAB]; 2];
    for (i, &t) in seq.iter().enumerate() {
        let toks = [t, (i as u32 * 13 + 1) % VOCAB as u32];
        batched.forward_one_batch(&toks, &mut bstates, &mut blogits);
    }
    assert_eq!(
        solo_logits, blogits[0],
        "lane 0 logits diverge from solo over the prefix"
    );

    // (a) Per-layer state bit-equality; v_first is the per-token TRANSIENT —
    // EMPTY at the token boundary on BOTH sides (the frame's 4th vec is a stub).
    for l in 0..LAYERS {
        let s = &solo.states[l];
        let lane = &bstates[l][0];
        assert_eq!(s.wkv, lane.wkv, "layer {l}: wkv lane != solo (bitwise)");
        assert_eq!(s.shift_x, lane.shift_x, "layer {l}: shift_x lane != solo");
        assert_eq!(
            s.channel_state, lane.channel_state,
            "layer {l}: channel_state lane != solo"
        );
        assert!(
            s.v_first.is_empty() && lane.v_first.is_empty(),
            "layer {l}: v_first not empty at token boundary (solo {} / lane {})",
            s.v_first.len(),
            lane.v_first.len()
        );
    }

    // (b) Hand-assemble the EXACT snapshot_state frame from both sides — the
    // cross-path byte-identity the wasm snapshot_lane_state export ships.
    let build_frame = |layers: &[&RWKV7LayerState]| -> Vec<u8> {
        let mut buf = Vec::new();
        put_u32(&mut buf, layers.len() as u32);
        for s in layers {
            put_f32s(&mut buf, &s.wkv);
            put_f32s(&mut buf, &s.shift_x);
            put_f32s(&mut buf, &s.channel_state);
            put_f32s(&mut buf, &s.v_first);
        }
        buf
    };
    let solo_refs: Vec<&RWKV7LayerState> = solo.states.iter().collect();
    let lane_refs: Vec<&RWKV7LayerState> = (0..LAYERS).map(|l| &bstates[l][0]).collect();
    let solo_frame = build_frame(&solo_refs);
    let lane_frame = build_frame(&lane_refs);
    assert_eq!(
        solo_frame, lane_frame,
        "snapshot frame bytes differ between solo and lane (bridge broken)"
    );

    // (c) Restore-roundtrips. Decode the LANE frame into a fresh SOLO pipeline and
    // the SOLO frame into a fresh whole-pipe LANE; continue 4 tokens on all three
    // paths — every step bit-identical to the uninterrupted solo run.
    let decode_into = |frame: &[u8], states: &mut [RWKV7LayerState]| {
        let mut off = 0usize;
        let n_layers = take_u32(frame, &mut off) as usize;
        assert_eq!(n_layers, LAYERS, "frame layer count");
        for s in states.iter_mut() {
            take_f32s(frame, &mut off, &mut s.wkv);
            take_f32s(frame, &mut off, &mut s.shift_x);
            take_f32s(frame, &mut off, &mut s.channel_state);
            take_f32s(frame, &mut off, &mut s.v_first);
        }
        assert_eq!(off, frame.len(), "frame fully consumed");
    };

    let mut resumed_solo = RWKV7Pipeline::from_knot(&cfg, build_rwkv7_backend().into_arc());
    decode_into(&lane_frame, &mut resumed_solo.states);

    let resumed_wave = RWKV7Pipeline::from_knot(&cfg, build_rwkv7_backend().into_arc());
    let mut rw_states = resumed_wave.new_batch_states(1);
    {
        // Mirror of the wasm restore_lane_state reader: [l][lane] target.
        let mut off = 0usize;
        let n_layers = take_u32(&solo_frame, &mut off) as usize;
        assert_eq!(n_layers, LAYERS, "solo frame layer count");
        for l in 0..n_layers {
            let s = &mut rw_states[l][0];
            take_f32s(&solo_frame, &mut off, &mut s.wkv);
            take_f32s(&solo_frame, &mut off, &mut s.shift_x);
            take_f32s(&solo_frame, &mut off, &mut s.channel_state);
            take_f32s(&solo_frame, &mut off, &mut s.v_first);
        }
        assert_eq!(off, solo_frame.len(), "solo frame fully consumed");
    }
    let mut rw_logits = vec![vec![0.0f32; VOCAB]; 1];

    let mut straight = vec![0.0f32; VOCAB];
    let mut resumed = vec![0.0f32; VOCAB];
    for &t in &cont {
        solo.forward_one(t, &mut straight); // uninterrupted reference
        resumed_solo.forward_one(t, &mut resumed);
        assert_eq!(straight, resumed, "token {t}: lane-frame→solo continuation diverges");
        resumed_wave.forward_one_batch(&[t], &mut rw_states, &mut rw_logits);
        assert_eq!(
            straight, rw_logits[0],
            "token {t}: solo-frame→lane continuation diverges"
        );
    }
}
